-- Initialize the random seed using os.time() combined with process/worker info
local function init_random_seed()
    local seed = os.time()
    -- Add additional entropy if available in OpenResty context
    if ngx and ngx.worker and ngx.worker.pid then
        seed = seed + ngx.worker.pid()
    else
        seed = seed + (os.clock() * 1000)
    end
    math.randomseed(seed)
    -- Burn a few random numbers to improve initial distribution
    for _ = 1, 10 do
        math.random()
    end
end

