-- Character set for token generation
local charset = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
local hex_chars = "0123456789abcdef"

-- Generate a random string of specified length from a given character pool
local function random_string(length, pool)
    pool = pool or charset
    local pool_len = #pool
    local result = {}
    for i = 1, length do
        local idx = math.random(1, pool_len)
        result[i] = string.sub(pool, idx, idx)
    end
    return table.concat(result)
end

-- Generate a hex string of specified length
local function random_hex(length)
    return random_string(length, hex_chars)
end

-- Generate a session token
-- Format: <prefix>_<timestamp_hex>_<random_part>
-- Default length of random part is 32 characters
function _M.generate_session_token(options)
    options = options or {}
    local prefix = options.prefix or "sess"
    local random_length = options.length or 32
    local timestamp = os.time()
    local timestamp_hex = string.format("%x", timestamp)
    local random_part = random_string(random_length)

    return prefix .. "_" .. timestamp_hex .. "_" .. random_part
end

-- Generate a nonce (Number used Once)
-- Returns a hex string suitable for CSRF protection and replay attack prevention
function _M.generate_nonce(length)
    length = length or 32
    local timestamp_part = string.format("%x", os.time())
    local random_part = random_hex(length)
    return timestamp_part .. random_part
end

-- Generate a simple API key
-- Format: <random_hex_block>-<random_hex_block>-<random_hex_block>-<random_hex_block>
function _M.generate_api_key()
