-- Clean up expired sessions
local function cleanup_expired_sessions()
    local now = os.time()
    local expired_keys = {}
    for token, session_data in pairs(sessions) do
        if session_data.expires_at and session_data.expires_at <= now then
            expired_keys[#expired_keys + 1] = token
        end
    end
    for _, token in ipairs(expired_keys) do
        sessions[token] = nil
    end
    return #expired_keys
end

-- Count active sessions
local function count_sessions()
    local count = 0
    for _ in pairs(sessions) do
        count = count + 1
    end
    return count
end

-- Create a new session
-- Returns session_token, session_data table
function _M.create_session(user_data, options)
    options = options or {}

    -- Cleanup if we're approaching max sessions
    if count_sessions() >= config.max_sessions then
        cleanup_expired_sessions()
        -- If still at max, reject
        if count_sessions() >= config.max_sessions then
            return nil, "Maximum session limit reached"
        end
    end

    local ttl = options.ttl or config.session_ttl
    local now = os.time()

    local token = _M.generate_session_token({
        prefix = options.prefix or "sess",
        length = options.token_length or config.token_length,
    })

    local csrf_token = _M.generate_csrf_token()
    local nonce = _M.generate_nonce(config.nonce_length)

    local session_data = {
        token = token,
        csrf_token = csrf_token,
        nonce = nonce,
        user_data = user_data or {},
        created_at = now,
        last_accessed_at = now,
        expires_at = now + ttl,
        ttl = ttl,
        ip_address = options.ip_address or nil,
        user_agent = options.user_agent or nil,
        metadata = options.metadata or {},
    }

    sessions[token] = session_data

    return token, session_data
end

-- Retrieve a session by token
function _M.get_session(token)
    if not token then
        return nil, "Token is required"
    end

    local session_data = sessions[token]
    if not session_data then
        return nil, "Session not found"
    end

    local now = os.time()

    -- Check if session has expired
    if session_data.expires_at and session_data.expires_at <= now then
        sessions[token] = nil
        return nil, "Session expired"
    end

    -- Update last accessed time
    session_data.last_accessed_at = now

    return session_data
end

-- Validate a session token and optionally verify CSRF token
function _M.validate_session(token, csrf_token)
