    if csrf_token then
        if session_data.csrf_token ~= csrf_token then
            return false, "Invalid CSRF token"
        end
    end

    return true, session_data
end

-- Validate a nonce (check and invalidate - single use)
local used_nonces = {}

function _M.validate_nonce(nonce, session_token)
    if not nonce then
        return false, "Nonce is required"
    end

    -- Check if nonce has already been used
    if used_nonces[nonce] then
        return false, "Nonce already used"
    end

    -- If session token provided, verify the nonce belongs to this session
    if session_token then
        local session_data = sessions[session_token]
        if not session_data then
            return false, "Session not found"
        end
        if session_data.nonce ~= nonce then
            return false, "Nonce does not match session"
        end
    end

    -- Mark nonce as used
    used_nonces[nonce] = os.time()

    return true
end

-- Refresh a session's token (token rotation for security)
function _M.refresh_session(old_token)
    local session_data, err = _M.get_session(old_token)
    if not session_data then
        return nil, err
    end

    -- Generate new token and security tokens
    local new_token = _M.generate_session_token({
        length = config.token_length,
