    session_data.csrf_token = new_csrf_token
    session_data.nonce = new_nonce
    session_data.last_accessed_at = os.time()

    -- Extend expiry on refresh
    session_data.expires_at = os.time() + session_data.ttl

    -- Store under new token and remove old
    sessions[new_token] = session_data
    sessions[old_token] = nil

    return new_token, session_data
end

