-- OpenResty-specific: Middleware handler for session validation
-- Use in access_by_lua_block
function _M.access_handler(options)
    options = options or {}
    local cookie_name = options.cookie_name or "session_token"
    local csrf_header = options.csrf_header or "X-CSRF-Token"
    local exempt_paths = options.exempt_paths or {}

    -- Check if current path is exempt
    if ngx then
        local uri = ngx.var.uri
        for _, path in ipairs(exempt_paths) do
            if uri == path or string.find(uri, path, 1, true) == 1 then
                return true
            end
        end

        -- Extract session token from cookie
        local token = ngx.var["cookie_" .. cookie_name]
        if not token then
            ngx.status = 401
            ngx.header["Content-Type"] = "application/json"
            ngx.say('{"error": "Authentication required", "code": "NO_SESSION"}')
            return ngx.exit(401)
        end

        -- Validate session
        local session_data, err = _M.get_session(token)
        if not session_data then
            ngx.status = 401
            ngx.header["Content-Type"] = "application/json"
            ngx.say('{"error": "' .. (err or "Invalid session") .. '", "code": "INVALID_SESSION"}')
            return ngx.exit(401)
        end

        -- For non-GET requests, validate CSRF token
        local method = ngx.req.get_method()
        if method ~= "GET" and method ~= "HEAD" and method ~= "OPTIONS" then
            local csrf_token = ngx.req.get_headers()[csrf_header]
            if not csrf_token or csrf_token ~= session_data.csrf_token then
                ngx.status = 403
                ngx.header["Content-Type"] = "application/json"
                ngx.say('{"error": "Invalid CSRF token", "code": "CSRF_FAILURE"}')
                return ngx.exit(403)
            end
        end

        -- Store session data in ngx.ctx for downstream use
        ngx.ctx.session = session_data
        ngx.ctx.session_token = token

        return true
    end

    return false, "Not running in OpenResty context"
end

-- OpenResty-specific: Set session cookie
function _M.set_session_cookie(token, options)
    if not ngx then
        return false, "Not running in OpenResty context"
    end

    options = options or {}
    local cookie_name = options.cookie_name or "session_token"
    local path = options.path or "/"
    local domain = options.domain or nil
    local secure = options.secure ~= false  -- default true
    local http_only = options.http_only ~= false  -- default true
    local same_site = options.same_site or "Strict"
    local max_age = options.max_age or config.session_ttl

    local cookie_parts = {
        cookie_name .. "=" .. token,
        "Path=" .. path,
        "Max-Age=" .. max_age,
        "SameSite=" .. same_site,
    }

    if domain then
        cookie_parts[#cookie_parts + 1] = "Domain=" .. domain
    end
    if secure then
        cookie_parts[#cookie_parts + 1] = "Secure"
    end
    if http_only then
        cookie_parts[#cookie_parts + 1] = "HttpOnly"
    end

    local cookie_string = table.concat(cookie_parts, "; ")
    ngx.header["Set-Cookie"] = cookie_string

    return true
end

-- OpenResty-specific: Clear session cookie
function _M.clear_session_cookie(options)
    if not ngx then
        return false, "Not running in OpenResty context"
    end

    options = options or {}
    local cookie_name = options.cookie_name or "session_token"
    local path = options.path or "/"

    local cookie_string = cookie_name .. "=; Path=" .. path .. "; Max-Age=0; HttpOnly; Secure; SameSite=Strict"
    ngx.header["Set-Cookie"] = cookie_string

    return true
end

-- Login handler - creates session and sets cookie
function _M.login(user_data, options)
    options = options or {}

    local ip_address = nil
    local user_agent = nil

    if ngx then
        ip_address = ngx.var.remote_addr
        user_agent = ngx.req.get_headers()["User-Agent"]
    end

    local token, session_data = _M.create_session(user_data, {
        ip_address = ip_address,
        user_agent = user_agent,
        ttl = options.ttl or config.session_ttl,
        metadata = options.metadata,
    })

    if not token then
        return nil, session_data  -- session_data contains error message
    end

    -- Set cookie if in OpenResty context
    if ngx then
        _M.set_session_cookie(token, options)
    end

    return token, session_data
end

-- Logout handler - destroys session and clears cookie
function _M.logout(token, options)
    options = options or {}

    if not token and ngx then
        local cookie_name = options.cookie_name or "session_token"
        token = ngx.var["cookie_" .. cookie_name]
    end

    if token then
        _M.destroy_session(token)
    end

    if ngx then
        _M.clear_session_cookie(options)
    end

    return true
end

return _M